import React, {type ChangeEventHandler, type Ref, useEffect, useRef, useState} from "react";
import {useUploader} from "../MainUploader";
import {useDrop} from "react-dnd";
import {NativeTypes} from "react-dnd-html5-backend";
import {checkExtAgainstAccepted, type ISelectedFile} from "@lmb-it/kitsconcerto-types";
import {Tooltip} from "primereact/tooltip";
import {Button, Flex, Text} from "../../../_compat";
import {useLanguage} from "../../../_compat";

const generateUniqueID = () => {
    return Math.floor(Math.random() * 100);
};

const MultipleImageUploader = () => {
    const {
        onChangeAnyFileUploader,
        limit,
        acceptedMemes,
        files,
        removeFile,
        isClassicUploader,
        onInvalidInput,
        disabled,
    } = useUploader();

    const {t} = useLanguage();
    const fileInputRef = useRef<HTMLInputElement>(null);

    const [{canDrop, isOver}, drop] = useDrop(() => ({
        accept: [NativeTypes.FILE],
        canDrop: (item) => {
            if (
                item &&
                typeof item == "object" &&
                "files" in item &&
                Array.isArray(item.files) &&
                item.files.length > 0
            ) {
                return (
                    item.files.filter((file) => {
                        if (file && "name" in file) {
                            const isGranted = checkExtAgainstAccepted(
                                file.name,
                                acceptedMemes
                            );
                            if (!isGranted) {
                                onInvalidInput(t("typeNotSupported"));
                            }
                            return isGranted;
                        }
                        return false;
                    }).length == item.files.length
                );
            }
            return false;
        },
        drop: (item) => {
            if (
                item &&
                typeof item == "object" &&
                "files" in item &&
                Array.isArray(item.files) &&
                item.files.length > 0
            ) {
                const files = item.files as File[];
                // @ts-ignore
                onChangeAnyFileUploader(files);
            }
        },
        collect: (monitor) => ({
            isOver: monitor.isOver(),
            canDrop: monitor.canDrop(),
        }),
    }));
    const isActive = canDrop && isOver;

    const onClickUpload = () => {
        fileInputRef.current && fileInputRef.current.click();
    };

    const onFileChange: ChangeEventHandler<Partial<HTMLInputElement>> = (
        e: any
    ) => {
        const inputFiles = e.target.files;
        if (inputFiles) {
            const sum = files.length + inputFiles.length;
            if (sum <= limit) {
                onChangeAnyFileUploader(inputFiles);
            } else {
                onInvalidInput(t("maximumAllowedFiles", limit));
            }
        }
    };

    const ImagePreview = ({imageFile}: { imageFile: ISelectedFile }) => {
        const [imageToPreview, setImageToPreview] = useState<any>("");
        const uniqueId = generateUniqueID();

        useEffect(() => {
            if (files.length > 0) {
                if (imageFile.file instanceof File) {
                    const reader = new FileReader();
                    reader.readAsDataURL(imageFile.file);
                    reader.onloadend = function () {
                        setImageToPreview(reader.result);
                    };
                } else if (typeof imageFile.file === "string") {
                    const isGranted = checkExtAgainstAccepted(
                        imageFile.ext,
                        acceptedMemes
                    );
                    if (!isGranted) {
                        setImageToPreview(imageFile.file);
                    }
                } else {
                    const isGranted = checkExtAgainstAccepted(
                        imageFile.file.uri,
                        acceptedMemes
                    );
                    if (isGranted) {
                        setImageToPreview(imageFile.file.uri);
                    }
                }
            }
        }, [files, imageFile, acceptedMemes]);

        return (
            <>
                <Tooltip
                    target={`.${uniqueId}`}
                    autoHide={true}
                    style={{padding: 0}}
                    mouseTrackLeft={10}
                >
                    <img
                        style={{objectFit: "cover", width: 200}}
                        alt="Preview"
                        src={imageToPreview}
                    />
                </Tooltip>
                <img
                    className={`image-preview ${uniqueId}`}
                    style={{objectFit: "cover", width: 50, height: 50, borderRadius: 6}}
                    alt="Preview"
                    src={imageToPreview}
                />
            </>
        );
    };

    return (
        <Flex flexDirection={"column"}
              className={disabled ? 'p-disabled' : ''}
              borderRadius={'inherit'}
              w={"full"}
              gap={8}>
            {!isClassicUploader && (
                <Flex
                    w={"full"}
                    flexDirection={"column"}
                    borderRadius={'inherit'}
                    onClick={onClickUpload}
                    cursor={"pointer"}
                    ref={drop as unknown as Ref<HTMLDivElement>}
                >
                    <Flex
                        borderW={2}
                        borderStyle={"dashed"}
                        borderColor={isActive ? "primary" : "surface-300"}
                        borderRadius={'inherit'}
                        bgColor={isActive ? "highlight-bg" : "transparent"}
                        borderRadiusLeft={"lg"}
                        borderRadiusRight={"lg"}
                        alignItems={"center"}
                        justifyContent={"center"}
                        flexDirection={"column"}
                        py={32}
                        px={16}
                        gap={8}
                        w={"full"}
                        className={"dropping_area"}
                        style={{transition: "border-color 0.2s, background-color 0.2s"}}
                    >
                        <Text fontSize={32} color={"primary"}>
                            <i className="pi pi-cloud-upload"/>
                        </Text>
                        <Text fontSize={14} color={"text-secondary"} textAlign={"center"}>
                            {isActive ? t("filesBeingDropped") : t("clickOrDragToUpload")}
                        </Text>
                    </Flex>
                    {files.length > 0 && (
                        <Text fontSize={13} color={"text-secondary"} textAlign={"center"} mt={4}>
                            {t("filesSelected", files.length)} / {limit}
                        </Text>
                    )}
                </Flex>
            )}

            {isClassicUploader && (
                <>
                    {files.map((file, index) => (
                        <Flex
                            justifyContent={"space-between"}
                            alignItems={"center"}
                            flexDirection={"row"}
                            key={index}
                            w={"full"}
                            gap={8}
                        >
                            <Flex gap={8} alignItems={"center"} flex={1}>
                                <ImagePreview imageFile={file}/>
                                <Text
                                    as={"span"}
                                    fontSize={13}
                                    color={"text-secondary"}
                                    textOverflow={"ellipsis"}
                                    whiteSpace={"nowrap"}
                                >
                                    {file.shortName}
                                </Text>
                            </Flex>
                            <Button
                                aria-label={t("remove")}
                                size={"sm"}
                                severity={"danger"}
                                icon={"pi pi-times"}
                                onClick={removeFile(index)}
                            />
                        </Flex>
                    ))}

                    <Flex
                        flex={1}
                        onClick={onClickUpload}
                        cursor={"pointer"}
                        ref={drop as unknown as Ref<HTMLDivElement>}
                    >
                        <Flex
                            borderW={2}
                            borderStyle={"dashed"}
                            borderColor={isActive ? "primary" : "surface-300"}
                            bgColor={isActive ? "highlight-bg" : "transparent"}
                            borderRadiusLeft={"lg"}
                            borderRadiusRight={"lg"}
                            alignItems={"center"}
                            justifyContent={"center"}
                            flexDirection={"column"}
                            py={16}
                            px={16}
                            gap={8}
                            w={"full"}
                            className={"dropping_area"}
                            style={{transition: "border-color 0.2s, background-color 0.2s"}}
                        >
                            <Text fontSize={24} color={"primary"}>
                                <i className="pi pi-cloud-upload"/>
                            </Text>
                            <Text fontSize={13} color={"text-secondary"} textAlign={"center"}>
                                {isActive ? t("filesBeingDropped") : t("dragFilesHere")}
                            </Text>
                        </Flex>
                    </Flex>
                </>
            )}

            <input
                ref={fileInputRef}
                hidden
                multiple
                type={"file"}
                accept={acceptedMemes.length > 0 ? acceptedMemes.join(",") : "*"}
                onChange={onFileChange}
            />
        </Flex>
    );
};

export default MultipleImageUploader;
